object SafeSqlBuilder {

  case class SqlFragment(builder: SQLActionBuilder)

  /**
   * Combines multiple SQL fragments with AND.
   * Uses Slick's sql interpolator which creates PreparedStatement parameters,
   * preventing SQL injection.
   */
  def combineWithAnd(fragments: Seq[SQLActionBuilder]): Option[SQLActionBuilder] = {
    fragments match {
      case Seq() => None
      case Seq(single) => Some(single)
      case head +: tail =>
        Some(tail.foldLeft(head) { (acc, fragment) =>
          concat(acc, sql" AND ", fragment)
        })
    }
  }

  def concat(a: SQLActionBuilder, b: SQLActionBuilder, c: SQLActionBuilder): SQLActionBuilder = {
    concat(concat(a, b), c)
  }

  def concat(a: SQLActionBuilder, b: SQLActionBuilder): SQLActionBuilder = {
    SQLActionBuilder(a.queryParts ++ b.queryParts, new SetParameter[Unit] {
      def apply(param: Unit, pp: slick.jdbc.PositionedParameters): Unit = {
        a.unitPConv.apply(param, pp)
        b.unitPConv.apply(param, pp)
      }
    })
  }
}

